module uartReceiver(
    input clk,
    input reset,
    input rx,
    input baud_rate,
    output reg [7:0] data,
    output reg data_valid
);

// Internal signals
reg [3:0] count;
reg [3:0] bit_count;
reg [7:0] shift_reg;
reg rx_reg;
reg start_bit_detected;
reg stop_bit_detected;
reg baud_tick;

// Baud rate generator
reg [31:0] baud_count;
always @(posedge clk) begin
    if (reset) begin
        baud_count <= 0;
        baud_tick <= 0;
    end else begin
        baud_count <= baud_count + 1;
        if (baud_count == (50000000 / baud_rate) - 1) begin
            baud_count <= 0;
            baud_tick <= 1;
        end else begin
            baud_tick <= 0;
        end
    end
end

// Receiver state machine
parameter IDLE = 2'b00;
parameter START_BIT = 2'b01;
parameter DATA_BITS = 2'b10;
parameter STOP_BIT = 2'b11;
reg [1:0] state;
always @(posedge clk) begin
    if (reset) begin
        state <= IDLE;
        count <= 0;
        bit_count <= 0;
        shift_reg <= 0;
        rx_reg <= 1;
        start_bit_detected <= 0;
        stop_bit_detected <= 0;
        data_valid <= 0;
    end else begin
        case (state)
            IDLE: begin
                if (rx_reg == 0 && baud_tick) begin
                    state <= START_BIT;
                    count <= 0;
                    bit_count <= 0;
                    shift_reg <= 0;
                    start_bit_detected <= 1;
                end else begin
                    state <= IDLE;
                end
            end
            START_BIT: begin
                if (count == 4) begin
                    if (rx_reg == 1) begin
                        state <= DATA_BITS;
                        count <= 0;
                    end else begin
                        state <= IDLE;
                        start_bit_detected <= 0;
                    end
                end else begin
                    count <= count + 1;
                end
            end
            DATA_BITS: begin
                if (count == 8) begin
                    state <= STOP_BIT;
                    count <= 0;
                end else begin
                    if (baud_tick) begin
                        shift_reg <= {shift_reg[6:0], rx_reg};
                        count <= count + 1;
                    end
                end
            end
            STOP_BIT: begin
                if (count == 4) begin
                    if (rx_reg == 1) begin
                        state <= IDLE;
                        stop_bit_detected <= 1;
                        data <= shift_reg;
                        data_valid <= 1;
                    end else begin
                        state <= IDLE;
                        start_bit_detected <= 0;
                    end
                end else begin
                    count <= count + 1;
                end
            end
            default: begin
                state <= IDLE;
            end
        endcase
    end
end

// Input sampling
always @(posedge clk) begin
    if (reset) begin
        rx_reg <= 1;
    end else begin
        if (baud_tick) begin
            rx_reg <= rx;
        end
    end
end

endmodule
```

