module traffic_light_controller(
    input clk,
    input pedestrian_request,
    output reg green,
    output reg yellow,
    output reg red
);

    // Local parameters
    parameter GREEN_TIME = 20;
    parameter YELLOW_TIME = 5;
    parameter RED_TIME = 15;
    parameter PEDESTRIAN_TIME = 10;

    // Local signals and registers
    reg [3:0] state;
    reg [4:0] counter;
    reg pedestrian_flag;

    // State machine
    always @(posedge clk) begin
        // Normal cycle
        if (!pedestrian_flag) begin
            case (state)
                2'b00: begin // Green
                    green <= 1'b1;
                    yellow <= 1'b0;
                    red <= 1'b0;
                    if (counter == GREEN_TIME - 1) begin
                        state <= 2'b01; // Transition to yellow
                        counter <= 0;
                    end else begin
                        counter <= counter + 1;
                    end
                end
                2'b01: begin // Yellow
                    green <= 1'b0;
                    yellow <= 1'b1;
                    red <= 1'b0;
                    if (counter == YELLOW_TIME - 1) begin
                        state <= 2'b10; // Transition to red
                        counter <= 0;
                    end else begin
                        counter <= counter + 1;
                    end
                end
                2'b10: begin // Red
                    green <= 1'b0;
                    yellow <= 1'b0;
                    red <= 1'b1;
                    if (counter == RED_TIME - 1) begin
                        state <= 2'b00; // Transition to green
                        counter <= 0;
                    end else begin
                        counter <= counter + 1;
                    end
                end
            endcase
        // Pedestrian flag is set
        end else begin
            green <= 1'b0;
            yellow <= 1'b0;
            red <= 1'b1;
            if (counter == PEDESTRIAN_TIME - 1) begin
                state <= 2'b00; // Transition to green
                counter <= 0;
                pedestrian_flag <= 0;
            end else begin
                counter <= counter + 1;
            end
        end
    end

    // Pedestrian request interrupt
    always @(posedge clk) begin
        if (pedestrian_request && state != 2'b10) begin // Only interrupt if not already red
            pedestrian_flag <= 1;
            state <= 2'b10; // Transition to red
            counter <= 0;
        end
    end

endmodule
