module shift_register(
    input clk,
    input areset,  // async active-high reset to zero
    input load,
    input ena,
    input [3:0] data,
    output reg [3:0] q);

    reg [3:0] shift_reg;
    reg [1:0] shift_dir;

    always @(posedge clk or posedge areset) begin
        if (areset) begin
            shift_reg <= 4'b0;
            shift_dir <= 2'b0;
        end else if (load) begin
            shift_reg <= data;
        end else if (ena) begin
            case (shift_dir)
                2'b00: shift_reg <= {shift_reg[2:0], shift_reg[3]};
                2'b01: shift_reg <= {shift_reg[3], shift_reg[2:0]};
                2'b10: shift_reg <= {shift_reg[1:0], shift_reg[3:2]};
                2'b11: shift_reg <= {shift_reg[3:2], shift_reg[1:0]};
            endcase
        end
    end

    always @(posedge clk or posedge areset) begin
        if (areset) begin
            q <= 4'b0;
        end else begin
            q <= shift_reg;
        end
    end

    always @(*) begin
        if (ena) begin
            case (shift_dir)
                2'b00: q = {shift_reg[2:0], shift_reg[3]};
                2'b01: q = {shift_reg[3], shift_reg[2:0]};
                2'b10: q = {shift_reg[1:0], shift_reg[3:2]};
                2'b11: q = {shift_reg[3:2], shift_reg[1:0]};
            endcase
        end
    end

    always @(posedge clk or posedge areset) begin
        if (areset) begin
            shift_dir <= 2'b0;
        end else if (ena) begin
            shift_dir <= {shift_dir[0], ena};
        end
    end

endmodule
