module fsm_4bit_counter (
  input clk,
  input reset,
  input enable,
  output reg [3:0] count,
  output reg valid
);

  parameter IDLE = 2'b00;
  parameter COUNT_UP = 2'b01;
  parameter COUNT_DOWN = 2'b10;
  parameter DONE = 2'b11;

  reg [1:0] state;

  always @(posedge clk) begin
    if (reset) begin
      state <= IDLE;
      count <= 4'b0000;
      valid <= 0;
    end
    else begin
      case (state)
        IDLE: begin
          count <= 4'b0000;
          valid <= 0;
          if (enable) begin
            if (count == 4'b1111) begin
              state <= DONE;
            end
            else begin
              state <= COUNT_UP;
            end
          end
        end

        COUNT_UP: begin
          count <= count + 1;
          valid <= 0;
          if (count == 4'b1111) begin
            state <= DONE;
          end
          else if (!enable) begin
            state <= IDLE;
          end
        end

        COUNT_DOWN: begin
          count <= count - 1;
          valid <= 0;
          if (count == 4'b0000) begin
            state <= DONE;
          end
          else if (!enable) begin
            state <= IDLE;
          end
        end

        DONE: begin
          valid <= 1;
          if (enable) begin
            if (count == 4'b1111) begin
              state <= COUNT_DOWN;
            end
            else begin
              state <= COUNT_UP;
            end
          end
          else begin
            state <= IDLE;
          end
        end
      endcase
    end
  end

endmodule
