module digital_lock(
    input clk,
    input reset,      // Synchronous active-high reset
    input [3:0] code,
    output unlock
);

    // Define the state machine states
    parameter IDLE = 2'b00;
    parameter COUNTING = 2'b01;
    parameter COMPARING = 2'b10;
    parameter UNLOCKED = 2'b11;

    // Define the state machine inputs
    reg [1:0] state;
    reg [3:0] count;
    reg [3:0] compare;
    reg sub;
    wire [3:0] sum;

    // Instantiate the adder modules
    ripple_adder adder1(.a(count), .b(4'b1), .cin(1'b0), .s(sum[0]), .cout(carry1));
    ripple_adder adder2(.a(sum), .b(compare), .cin(sub), .s(sum), .cout(carry2));

    // Instantiate the comparator module
    comparator cmp(.a(count), .b(compare), .sub(sub));

    // Define the unlock output
    assign unlock = (state == UNLOCKED);

    // Define the state machine
    always @(posedge clk) begin
        if (reset) begin
            state <= IDLE;
            count <= 4'b0;
            compare <= code;
            sub <= 1'b0;
        end else begin
            case (state)
                IDLE: begin
                    if (count == 4'b0) begin
                        state <= COUNTING;
                    end else begin
                        count <= count - 1;
                    end
                end
                COUNTING: begin
                    if (count == 4'b1001) begin
                        state <= COMPARING;
                    end else begin
                        count <= count + 1;
                    end
                end
                COMPARING: begin
                    sub <= 1'b1;
                    if (cmp.eq) begin
                        state <= UNLOCKED;
                    end else begin
                        state <= COUNTING;
                    end
                end
                UNLOCKED: begin
                    state <= IDLE;
                    count <= 4'b0;
                    compare <= code;
                    sub <= 1'b0;
                end
            endcase
        end
    end

endmodule

// Define the ripple carry adder module
module ripple_adder(
    input [3:0] a,
    input [3:0] b,
    input cin,
    output [3:0] s,
    output cout
);

    wire [3:0] sum;
    wire [3:0] carry;

    assign sum = a ^ b ^ cin;
    assign carry = (a & b) | (a & cin) | (b & cin);

    assign s = sum;
    assign cout = carry;

endmodule

// Define the comparator module
module comparator(
    input [3:0] a,
    input [3:0] b,
    input sub,
    output eq
);

    wire [3:0] diff;

    assign diff = (sub) ? (a - b) : (a + b);

    assign eq = (diff == 4'b0);

endmodule
