        shifted_counter[0] <= counter[1];
        shifted_counter[1] <= counter[2];
        shifted_counter[2] <= counter[3];
        shifted_counter[3] <= counter[0];
    end
    else begin // No shift
        shifted_counter <= counter;
    end

    // Bitwise AND
