parameter RED_YELLOW_TIME = 25'd125000; // 1.25 seconds
parameter GREEN_TIME = 25'd750000; // 7.5 seconds
parameter YELLOW_TIME = 25'd125000; // 1.25 seconds

always @(posedge clk) begin
  if (reset) begin
    current_state <= 2'b00; // start with red light
    counter <= RED_TIME;
  end else begin
    case (current_state)
      2'b00: begin // red
        if (counter == 0) begin
          current_state <= 2'b01;
          counter <= RED_YELLOW_TIME;
        end else begin
          counter <= counter - 1;
        end
      end
      2'b01: begin // red-yellow
        if (counter == 0) begin
          current_state <= 2'b10;
          counter <= GREEN_TIME;
        end else begin
          counter <= counter - 1;
        end
      end
      2'b10: begin // green
        if (counter == 0) begin
          current_state <= 2'b11;
          counter <= YELLOW_TIME;
        end else begin
          counter <= counter - 1;
        end
      end
      2'b11: begin // yellow
        if (counter == 0) begin
          current_state <= 2'b00;
          counter <= RED_TIME;
        end else begin
          counter <= counter - 1;
        end
      end
    endcase
  end
end

