  full_adder FA2(.a(A[2]), .b(B[2]), .cin(carry[1]), .sum(sum[2]), .carry(carry[2]));
  full_adder FA3(.a(A[3]), .b(B[3]), .cin(carry[2]), .sum(sum[3]), .carry(Cout));

  assign S = sum;

endmodule
module half_adder (
  input a,
  input b,
  output sum,
  output carry
);

  assign sum = a ^ b;
  assign carry = a & b;

endmodule
module full_adder (
  input a,
  input b,
  input cin,
  output sum,
  output carry
);

  wire s1, c1, c2;

  // First half adder
  half_adder HA0(.a(a), .b(b), .sum(s1), .carry(c1));

  // Second half adder
  half_adder HA1(.a(s1), .b(cin), .sum(sum), .carry(c2));

  // Carry out
  assign carry = c1 | c2;

endmodule
