         busy <= 1'b0;
         data <= 8'b0;
      end else begin
         case (state)
            2'b00: begin // STATE_IDLE
               if (~rx_reg) begin
                  busy <= 1'b1;
                  state <= 2'b01;
                  baud_counter <= 0;
                  rx_counter <= 0;
               end
            end
            2'b01: begin // STATE_WAIT_HALF
               if (baud_counter == (CLK_DIV / 2) - 1) begin
                  state <= 2'b10;
                  baud_counter <= 0;
